SELECT Customer.No_, Customer.Name, Len([name]) AS t1, Customer.[Search Name], Len([Search Name]) AS t2, Customer.Address, Len([address]) AS t3, Customer.[Address 2], Len([address 2]) AS t4, Customer.City, Len([city]) AS t5, Customer.Placeholder, [Sales Header].[selling season code]
FROM [Sales Header] INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_
GROUP BY Customer.No_, Customer.Name, Len([name]), Customer.[Search Name], Len([Search Name]), Customer.Address, Len([address]), Customer.[Address 2], Len([address 2]), Customer.City, Len([city]), Customer.Placeholder, [Sales Header].[selling season code]
HAVING (((Len([name]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([Search Name]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([address]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([address 2]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([city]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione]));

